// src/components/Sidebar.js
import React from "react";
import "./Sidebar.css";

export default function Sidebar({ currentPage, navigate }) {
  return (
    <aside className="sidebar">
      {/* LOGO */}
      <div className="sidebar-logo">
        <img src="/assets/images/clario-logo.png" alt="CLARIO" />
      </div>

      {/* NAVIGATION */}
      <nav className="sidebar-nav">
        <button
          className={`nav-item ${currentPage === "home" ? "active" : ""}`}
          onClick={() => navigate("home")}
        >
          <span className="icon">🏠</span>
          Home
        </button>

        <button
          className={`nav-item ${currentPage === "practice" ? "active" : ""}`}
          onClick={() => navigate("practice")}
        >
          <span className="icon">🎤</span>
          Practice
        </button>

        {/* ❌ SCENARIOS REMOVED */}

        <button
          className={`nav-item ${currentPage === "progress" ? "active" : ""}`}
          onClick={() => navigate("progress")}
        >
          <span className="icon">📈</span>
          Progress
        </button>

        <div className="divider" />

        <button
          className={`nav-item ${currentPage === "settings" ? "active" : ""}`}
          onClick={() => navigate("settings")}
        >
          <span className="icon">⚙️</span>
          Settings
        </button>

        <button
          className="nav-item logout"
          onClick={() => navigate("logout")}
        >
          <span className="icon">↩</span>
          Log out
        </button>
      </nav>

      {/* PREMIUM CARD */}
      <div className="sidebar-premium">
        <div className="premium-icon">👑</div>
        <h4>Go Premium</h4>
        <p>
          Unlock advanced insights, personalized tips, and unlimited practice.
        </p>
        <button className="upgrade-btn">Upgrade Now</button>
      </div>
    </aside>
  );
}
